mapper.select:
select customer_id from customer_pool_view_allocation
where pool_id = #{poolId}
and user_id = #{userId}
and period_type = #{periodType}
and period_key = #{periodKey}

select a.customer_id from customer_pool_view_allocation a
left join customer c on a.customer_id = c.id
where a.pool_id = #{poolId}
and a.user_id = #{userId}
and a.period_type = #{periodType}
and a.period_key = #{periodKey}
and (c.owner is null

    or c.owner not in

        #{ownerId}


)

mapper.delete:
delete from customer_pool_view_allocation
where pool_id = #{poolId}
and user_id = #{userId}
and period_type = #{periodType}
and period_key = #{periodKey}

mapper.select:
select c.id from customer c
where c.pool_id = #{poolId}
and c.in_shared_pool is true

    and c.owner not in

        #{ownerId}


and c.id not in (
    select a2.customer_id from customer_pool_view_allocation a2
    where a2.pool_id = #{poolId}
    and a2.period_type = #{periodType}
    and a2.period_key = #{periodKey}
)
